window.optimizelyHelpers = {};

window.optimizelyHelpers.getCookie = function(name) {
    if (!navigator.cookieEnabled)
        return undefined;

    var match = document.cookie.match(name + '=([^;]*)');
    return match ? match[1] : undefined;
};

window.optimizelyHelpers.setCookie = function(c_name, value, exdays, c_domain) {
    if (!navigator.cookieEnabled)
        return undefined;

    c_domain = (typeof c_domain === "undefined") ? "" : "domain=" + c_domain + ";";
    var exdate = new Date();
    exdate.setDate(exdate.getDate() + exdays);
    var c_value = escape(value) + ((exdays == null) ? "" : "; expires=" + exdate.toUTCString());
    document.cookie = c_name + "=" + c_value + ";" + c_domain + "path=/";
};

window.optimizelyHelpers.deleteCookie = function(name) {
    if (!navigator.cookieEnabled)
        return undefined;
    document.cookie = name + '=; Path=/; Expires=Thu, 01 Jan 1970 00:00:01 GMT;';
};


function setVisitorIdCookie() {
    let tealium_id = window.optimizelyHelpers.getCookie("utag_main_v_id");
    let client_id = window.optimizelyHelpers.getCookie("client_visitor_id_test");
    

    if (!client_id) { //fresh session or just launched
        //persist existing tealium id using API
        if (tealium_id) { //just launched
            window.optimizelyHelpers.setCookie("server_visitor_id_test", tealium_id, 180);
        }
        callVisitorIdAPI(false); //synchronous
    }
    else if (client_id && !tealium_id) { //expected on devices with ITP after 7 days
        // window.optimizelyHelpers.setCookie("utag_main_v_id", client_id, 180, ".kmart.com.au"); // Do not set during testing
        callVisitorIdAPI(true); //asynchronous, just resetting the cookie
    }
}
function callVisitorIdAPI(isAsync) {
    const request = new XMLHttpRequest();
    let fetchStart = performance.now();
    if (isAsync){
        request.timeout = 5000;
    }
    request.onload = () => {
      if (request.readyState === request.DONE) {
        let fetchResponseTime = performance.now() - fetchStart;
        fetchResponseTime = fetchResponseTime.toFixed(0);
        let response = JSON.parse(request.response)
        let akamaiGrn = request.getResponseHeader("akamai-grn");
        let visitorId = response.server_visitor_id;
        if (visitorId) {
          logToNewRelicAPIResponse(fetchResponseTime, visitorId, akamaiGrn);
        }
      }
    };
    request.ontimeout = (e) => {
      let fetchResponseTime = performance.now() - fetchStart;
      fetchResponseTime = fetchResponseTime.toFixed(0);
      logToNewRelic("Visitor ID API Timeout (5000ms): " + err.message, fetchResponseTime);
    };
    
    request.open("GET", "/api/customer/visitor_id/", isAsync);
    request.send(null);
    //https://developer.mozilla.org/en-US/docs/Web/API/XMLHttpRequest/response
    //https://developer.mozilla.org/en-US/docs/Web/API/XMLHttpRequest/getResponseHeader
}

setVisitorIdCookie();

function logToNewRelic(eventstring,responseTime) {
    const pageviewPercentage = 100 //0.1, 1, 10, 100
    if(window.newrelic){
        window.newrelic.addPageAction("Tealium Tech Debt", {
            message: "PersistCookie " + pageviewPercentage + "%: " + eventstring,
            "TestPercentage": pageviewPercentage,
            "Request Uri": location.pathname,
            "ResponseTime": responseTime,
        });
    }
}

function logToNewRelicAPIResponse(responseTime, visitorID, akamaiGrn) {
    const pageviewPercentage = 100 //0.1, 1, 10, 100
    if(window.newrelic){
        window.newrelic.addPageAction("Tealium Tech Debt", {
            message: "PersistCookie Visitor ID Response " + pageviewPercentage + "%",
            "TestPercentage": pageviewPercentage,
            "Request Uri": location.pathname,
            "ResponseTime": responseTime,
            "VisitorID": visitorID,
            "akamaiGrn": akamaiGrn,
        });
    }
}

window.optimizelyHelpers.AudiencePDPCoFilter = function() {
  try{
  // var number_of_pageviews can be adjusted to the number of times you want visitors to see before they qualify for this audienc	
  var number_of_pageviews = 3;	
  // to calculate the date today	
  var d = new Date();	
  // visitors are by default not in this audience so we start with in_audience = false	
  var in_audience = false;	
  var query_output = optimizely.get('behavior').query({	
    version: '0.2',	
    filter: [{	
        field: ['type'],	
        value: 'pageview'	
       },	
      {	
        field: ["name"],	
        comparator: "is",	
        value: "pdp"	
      }	
    ],	
    pick: {	
      field: ["time"]	
    }	
  });	
  var count = 0;	
  // we check how many pageviews there were in the last 7 days (starting yesterday),
  //and set in_audience to true if the number is higher than "number_of_pageviews"	
  var yesterday = d.setDate(d.getDate()-1);	
  var last_week = d.setDate(d.getDate()-6);	
  for (var i = 0; i < query_output.length; i++) {	
  if(query_output[i]<yesterday && query_output[i]>last_week) {	
        count = count + 1;	
        if(count >= number_of_pageviews){	
        in_audience = true;	
        // break statement added here, to stop the for loop once the number_of_pageviews has been exceeded, for performance	
        break;	
        }	
    }
  }
	return in_audience;
  }catch(ex){
 
  }
};

window.optimizelyHelpers.debounce = function(func, wait, immediate) {
	var timeout;
	return function() {
		var context = this, args = arguments;
		var later = function() {
			timeout = null;
			if (!immediate) func.apply(context, args);
		};
		var callNow = immediate && !timeout;
		clearTimeout(timeout);
		timeout = setTimeout(later, wait);
		if (callNow) func.apply(context, args);
	};
};

window.optimizelyHelpers.throttle = function(fn, wait) {
  var time = Date.now();
  return function() {
    if ((time + wait - Date.now()) < 0) {
      fn();
      time = Date.now();
    }
  };
};

function setVisitorCookieId() {
    var uid = window.optimizelyHelpers.getCookie('optimizelyEndUserId') || "";
    var cookieID = "";
    if (/_/ig.test(uid)) {
        cookieID = "KmartID";
    } else {
        cookieID = "OptimizelyID";
    } 
    window["optimizely"].push({
        type: "user",
        attributes: {
            visitorCookieId: cookieID
        }
    });
};

setVisitorCookieId();


